import { useState, useEffect } from "@wordpress/element";

import {
	Button,
	SelectControl,
	Panel,
	PanelBody,
	PanelRow,
	Card,
	CardHeader,
	CardBody,
	Spinner,
	Notice,
	Animate,
} from "@wordpress/components";
import { __ } from "@wordpress/i18n";

//import EditableElement from "./EditableElement";

export default function WebfontSelector() {
	const [settings, setSettings] = useState({});
	const [previewText, setPreviewText] = useState(
		"Lorem ipsum dolor sit amet, consetetur sadipscing elitr"
	);
	const [rerenderKey, setRerenderKey] = useState(1);
	const [isSaving, setIsSaving] = useState(false);
	const [isLoading, setIsLoading] = useState(true);
	const [showSaveSuccess, setShowSaveSuccess] = useState(false);

	const loadSettings = () => {
		fetch(window.wphtmlmailWebfonts.restUrl + "webfontsettings")
			.then((resp) => resp.json())
			.then((data) => {
				const newSettings = { ...data };
				if (!("fontsets" in newSettings)) newSettings.fontsets = [];
				for (let fontsetIndex = 0; fontsetIndex <= 2; fontsetIndex++) {
					if (newSettings.fontsets.length <= fontsetIndex)
						newSettings.fontsets[fontsetIndex] = {
							googleFont: "",
							fallbackFont: "",
						};
				}
				setSettings(newSettings);
				setIsLoading(false);
			});
	};

	const saveSettings = () => {
		setIsSaving(true);
		const preparedSettings = { ...settings };
		preparedSettings.fontsets.forEach((fontset, fontsetIndex) => {
			if (
				preparedSettings.fontsets[fontsetIndex].googleFont &&
				preparedSettings.fontsets[fontsetIndex].fallbackFont
			) {
				preparedSettings.fontsets[fontsetIndex].name =
					"Fontset #" +
					(fontsetIndex + 1) +
					": " +
					preparedSettings.fontsets[fontsetIndex].googleFont;

				preparedSettings.fontsets[fontsetIndex].cssvalue =
					'"' +
					preparedSettings.fontsets[fontsetIndex].googleFont +
					'",' +
					preparedSettings.fontsets[fontsetIndex].fallbackFont;
			} else {
				preparedSettings.fontsets[fontsetIndex].name = "";
				preparedSettings.fontsets[fontsetIndex].cssvalue = "";
			}
		});
		var request = new Request(
			window.wphtmlmailWebfonts.restUrl + "webfontsettings",
			{
				method: "POST",
				body: JSON.stringify(preparedSettings),
				headers: { "Content-Type": "application/json" },
			}
		);
		fetch(request).then((resp) => {
			setIsSaving(false);
			setShowSaveSuccess(true);
			setTimeout(() => {
				setShowSaveSuccess(false);
			}, 4000);
		});
	};

	const refreshGoogleFontsStylesheetURL = (settings) => {
		let url = "";

		settings.fontsets.forEach((fontset) => {
			if (fontset.googleFont)
				url += "&family=" + fontset.googleFont.replace(" ", "+");
		});
		if (url === "") url = false;
		else url = "https://fonts.googleapis.com/css2?display=swap" + url;
		return url;
	};

	useEffect(() => {
		loadSettings();
	}, []);

	const renderFontset = (fontsetIndex) => {
		const googleFonts = [];
		window.wphtmlmailWebfonts.googleFonts.forEach((font) => {
			googleFonts.push({ label: font.family, value: font.family });
		});

		return (
			<PanelBody
				title={
					__("Fontset", "wp-html-mail-webfonts") +
					" #" +
					(fontsetIndex + 1) +
					(settings.fontsets[fontsetIndex].googleFont
						? ": " + settings.fontsets[fontsetIndex].googleFont
						: "")
				}
				initialOpen={fontsetIndex === 0}
				className="fontset"
				key={"fontset-" + fontsetIndex}
			>
				<PanelRow className="fontsetrow">
					<div className="fontselectcol">
						<SelectControl
							label={__(
								"Google Webfont",
								"wp-html-mail-webfonts"
							)}
							key={
								"google-font-select-" +
								fontsetIndex +
								rerenderKey
							}
							value={settings.fontsets[fontsetIndex].googleFont}
							options={[
								{ value: "", label: "-" },
								...googleFonts,
							]}
							onChange={(font) => {
								setSettings((settings) => {
									settings.fontsets[
										fontsetIndex
									].googleFont = font;
									settings.googleFontsStylesheetURL = refreshGoogleFontsStylesheetURL(
										settings
									);
									return settings;
								});

								setRerenderKey(
									(rerenderKey) => rerenderKey + 1
								);
							}}
						/>
					</div>
					<div className="previewcol">
						{settings.fontsets[fontsetIndex].googleFont && (
							<input
								className="previewtext"
								type="text"
								style={{
									fontFamily:
										settings.fontsets[fontsetIndex]
											.googleFont,
								}}
								value={previewText}
								onChange={(e) => {
									setPreviewText(e.target.value);
								}}
							/>
						)}
					</div>
				</PanelRow>
				<PanelRow className="fontsetrow">
					<div className="fontselectcol">
						<SelectControl
							label={__(
								"Alternative font",
								"wp-html-mail-webfonts"
							)}
							key={
								"fallback-font-select-" +
								fontsetIndex +
								rerenderKey
							}
							value={settings.fontsets[fontsetIndex].fallbackFont}
							options={[
								{ value: "", label: "-" },
								...window.wphtmlmailWebfonts.fallbackFonts,
							]}
							onChange={(font) => {
								setSettings((settings) => {
									settings.fontsets[
										fontsetIndex
									].fallbackFont = font;
									return settings;
								});
								setRerenderKey(
									(rerenderKey) => rerenderKey + 1
								);
							}}
						/>
					</div>
					<div className="previewcol">
						{settings.fontsets[fontsetIndex].fallbackFont && (
							<input
								className="previewtext"
								type="text"
								style={{
									fontFamily:
										settings.fontsets[fontsetIndex]
											.fallbackFont,
								}}
								value={previewText}
								onChange={(e) => {
									setPreviewText(e.target.value);
								}}
							/>
						)}
					</div>
				</PanelRow>
			</PanelBody>
		);
	};

	if (isLoading || !settings)
		return (
			<div className="mail-loader">
				<Spinner />
			</div>
		);
	else
		return (
			<React.Fragment>
				<div className="settings-editor">
					{showSaveSuccess && (
						<Notice status="success" isDismissible={false}>
							<p>
								{__(
									"Your settings have been saved. Go to the template tab now and use your new fonts.",
									"wp-html-mail-webfonts"
								)}
							</p>
						</Notice>
					)}

					<div className="save-button-pane components-panel__header">
						<Button
							isPrimary
							isBusy={isSaving}
							onClick={(e) => {
								e.preventDefault();
								saveSettings();
							}}
						>
							{__("Save settings", "wp-html-mail-webfonts")}
						</Button>
					</div>
					<div className="description">
						<h3>
							{__("Choose your fonts", "wp-html-mail-webfonts")}
						</h3>
						<p>
							{__(
								"Create up to three fontsets. Each of them consists of a webfont and a fallback font for email clients which do not support webfonts. Once defined here you can use them in your template and in our WooCommerce extension like any other font.",
								"wp-html-mail-webfonts"
							)}
						</p>
					</div>

					{"googleFontsStylesheetURL" in settings &&
						settings.googleFontsStylesheetURL && (
							<link
								key={"google-stylesheet-" + rerenderKey}
								rel="stylesheet"
								type="text/css"
								href={settings.googleFontsStylesheetURL}
							/>
						)}
					<Panel className="fontsets-panel">
						{settings.fontsets &&
							settings.fontsets.length > 0 &&
							settings.fontsets.map((fontset, fontsetIndex) =>
								renderFontset(fontsetIndex)
							)}
					</Panel>
				</div>
				<div className="info-sidebar">
					<Card>
						<CardHeader>
							<h3>
								{__(
									"Webfonts in emails",
									"wp-html-mail-webfonts"
								)}
							</h3>
						</CardHeader>
						<CardBody className="description">
							<p>
								{__(
									"As not all email clients can handle webfonts those who don't will show a different font family. To avoid each email client to pick its own favorite font you can define an alternativ font for each webfont you choose. Please keep in mind that your fallback font uses the same font size and style as the main one.",
									"wp-html-mail-webfonts"
								)}
							</p>
							<p>
								{__(
									"Currently these email clients support webfonts:",
									"wp-html-mail-webfonts"
								)}
							</p>
							<ul>
								<li>Apple Mail</li>
								<li>iOS Mail</li>
								<li>Google Android</li>
								<li>Samsung Mail (Android 8.0)</li>
								<li>Outlook for Mac</li>
								<li>Outlook App</li>
							</ul>
						</CardBody>
					</Card>
				</div>
			</React.Fragment>
		);
}
